      /* <flatten type="Javascript"> */
function load$EInvoice$(g) {
  g._$k = [], g._$ld = [], g._$lvd = [], g._$c = [];
  g._$i = g._getColumnOrder('stt_rec');
  g._$t = g._getColumnOrder('tag');
  g._$x = g._getColumnOrder('chuoi_ngay');
  g._$y = g._getColumnOrder('ngay_ct');
  g._$z = g._getColumnOrder('ma_kh');
  g.add_commandEvent(on$EInvoice$ExecuteCommand);
}
function dispose$EInvoice$(g) {
  g._$k = g._$ld = g._$lvd = g._$c = g._$i = g._$t = g._$x = g._$y = g._$z = null;
  try {g.remove_commandEvent(on$EInvoice$ExecuteCommand);} catch (ex) {}
  if (g._$certificate) {
    g._$certificate.dispose();
    g._$certificate = null;
  }
}
function scatter$GridReport$(g) {
  fill$Grid(g, true);
}
function load$ExternalScript(g) {
  var s = document.createElement('script');
  s.type = 'text/javascript';
  s.src = $func.resolveClientUrl(g._url$ExternalScript, g._baseUrl);
  document.getElementsByTagName('head')[0].appendChild(s);
}
/* </flatten> */
function on$EInvoice$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, id = g.get_id();
  switch (action) {
    case 'Release':
      if (!g._$resign) {
        if (g._$process == 9 || !isCheck$Grid(g)) break;
        if (g._use$Token) {
          if (!g._$certificate) g._$certificate = new FastBusiness.AjaxControlExtender.Certificate(null, g, g.get_id());
          if (!g._$certificate.checkPlugin(g)) break;
        }
        var v = (g._language == 'v');
        var m1 = (v ? 'Chỉ chọn một chứng từ khi ' + get$ProcessString(g, v) + '.' : 'Please select only one voucher at a time.'),
            m2 = (v ? 'Hệ thống sẽ <span class="Highlight">xác thực các chứng từ đang được chọn</span>, bạn có chắc chắn thực hiện không?' : 'Are you sure you want to <span class="Highlight">release selected vouchers</span>?');

        if (g._$voucherBook) m2 = String.format(v ?
            'Hệ thống sẽ xác thực các chứng từ đang được chọn theo mẫu số <span class="Highlight">{0}</span>, ký hiệu <span class="Highlight">{1}</span>, bạn có chắc chắn thực hiện không?' :
            'The system will authenticate the selected vouchers by the number <span class="Highlight">{0}</span>, series <span class="Highlight">{1}</span>, are you sure you want to release?'
          , g._$form, g._$series);

        if (g._import$Invoice && !g._allowMultiCheck && g._$k.length > 1) {
          $message.show(m1, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
          break;
        }
        $message.show(m2, 0, String.format('request$EIProcess($find(\'{0}\'));', id), String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
        break;
      }
      else {
        if (g._$process != 9 || g._unitProvider != 8 || !isCheck$Grid(g)) return;
        if (g._$k.length > 1) {
          var v = (g._language == 'v');
          var m1 = (v ? 'Chỉ chọn một chứng từ khi điều chỉnh thông tin.' : 'Please select only one voucher at a time.')
          $message.show(m1, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
          return;
        }
        if (g._use$Token) {
          if (!g._$certificate) g._$certificate = new FastBusiness.AjaxControlExtender.Certificate(null, g, id);
          if (!g._$certificate.checkPlugin(g)) break;
        }
        g.showForm('ESTranAdjust');
        break;
      }
    case 'Cancel':
      if (g._$process != 9 || g._$resign || !isCheck$Grid(g)) break;
      if (g._$k.length > 1) {
        $message.show(g._language == 'v' ? 'Chỉ chọn một chứng từ khi hủy.' : 'Please select only one voucher at a time.', String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
        break;
      }
      g.showForm('ESTranCancel');
      break;
    case 'Print':
      e.type.cancelEvent = true;
      if (g._$process != 9 && g._activeRow > -1 && g._allowPreview) {
        var l1 = g._getItemValue(g._activeRow, g._getColumnOrder('stt_rec')), l2 = g._getItemValue(g._activeRow, g._getColumnOrder('ma_ct')), l3 = g._getItemValue(g._activeRow, g._getColumnOrder('ma_dvcs')), l4 = g._getItemValue(g._activeRow, g._getColumnOrder('ngay_ct')).format('yyyyMMdd'), l5 = g._getItemValue(g._activeRow, g._getColumnOrder('ma_kh'));
        var l6 = '319';
        var t = $get('requestFormData'), innerHTML = null;
        if (!t) t = $func.requestFormData();
        if (t) innerHTML = t.innerHTML;
        t.innerHTML = '<input type="hidden" name="k" id="k"/><input type="hidden" name="v" id="v"/><input type="hidden" name="u" id="u"/><input type="hidden" name="h" id="h"/><input type="hidden" name="d" id="d"/><input type="hidden" name="e" id="e"/><input type="hidden" name="c" id="c"/><input type="hidden" name="a" id="a"/><input type="hidden" name="m" id="m"/><input type="hidden" name="t" id="t"/>';
        t.action = $func.resolveClientUrl('~/AppHandler/EInvoice.ashx', g._baseUrl);
        $get('k', t).value = l1;
        $get('v', t).value = l2;
        $get('u', t).value = l3;
        $get('h', t).value = '';
        $get('d', t).value = l4;
        $get('e', t).value = g._$voucherBook;
        $get('c', t).value = l5;
        $get('a', t).value = '600';
        $get('m', t).value = l6;
        $get('t', t).value = '&DetailTaxFlag;&EICustomerAuthentication;&EINoteFlag;';
        if (!$func.isIE) t.target = '_blank';
        t.submit();
        if (g._activeCell) g._activeCell.focus();
        if (innerHTML) t.innerHTML = innerHTML;
      }
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function get$ProcessString(g, v) {return (g._$process == 1 ? (v ? 'xác thực' : 'release') : (g._$process == 2 ? (v ? 'điều chỉnh' : 'adjust') : (v ? 'thay thế' : 'replace')));}
/* </flatten> */
function request$EIProcess(g, force) {
  var id = g._id;
  if (!force) {
     $func.showWait(id);
     window.setTimeout(function() {request$EIProcess(g, true);}, 2);
     return;
  }

  var m = (g._import$Invoice == 1 ? '311' : '319'), a = ((g._use$Token && g._unitProvider != 2) ? '300' : null);
  var query = Sys.Serialization.JavaScriptSerializer.serialize({
    'dFrom': $func.formatDateOrder(g._$dFrom),
    'dTo': $func.formatDateOrder(g._$dTo),
    'unit': g._$unit,
    'voucherCode': g._$voucherCode,
    'idNumber': g._$k.toString(),
    'listDays': g._$ld.toString(),
    'voucherDate': g._$lvd.toString(),
    'customerList': g._$c.toString(),
    'voucherBook': g._$voucherBook.toString(),
    'debugMode': g._$debugMode,
    'external': '&DetailTaxFlag;&EICustomerAuthentication;&EINoteFlag;'
  });

  Sys.Net.WebServiceProxy.invoke($func.resolveClientUrl(g._url$EInvoice, g._baseUrl), g._service$Method, false, {
      method: m,
      action: a,
      query: query
  }, onRequest$Completed, onRequest$Failed, g._id);
}
/* <flatten type="Javascript"> */
function onRequest$Completed(r, id) {
  var g = $find(id), msg, v = g._language == 'v', refresh = true;
  if (g._$debugMode == 1 && r.Success == '2') {
    $func.hideWait(id);
    g._busy(false);
    g._debug$Data = r;
    g.showForm('ESTranForm');
    return;
  }
  if (r.Success == '1') {
    msg = v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.';
    if ((g._use$Token && (g._unitProvider == 1 || g._unitProvider == 8)) && !g._import$Invoice) {
      g._$process = 4;
      g._$certificate.onRequestTokenCompleted(r, g, id);
      return;
    }
  } else {
    if (r.Code != '-1') {
      refresh = false;
      var c = r.Field;
      switch (r.Code) {
        case '1':
          msg = String.format(v ?
            'Hóa đơn số <span class="Highlight">{0}</span> đã được sửa hoặc xóa bởi người sử dụng khác.' :
            'The voucher number <span class="Highlight">{0}</span> has been modified or deleted by another user.',
          c);
          break;
        case '2':
          msg = String.format(v ?
            'Phát sinh lỗi trong quá trình điều chỉnh chứng từ số <span class="Highlight">{0}</span>, chương trình không thể tiếp tục thực hiện được.' :
            'An error occurred while processing the voucher number <span class="Highlight">{0}</span>, The process could not continue running.',
          c);
          break;
        case '3':
          msg = String.format(v ?
            'Đơn vị <span class="Highlight">{0}</span> chưa khai báo tài khoản kết nối, chương trình không thể tiếp tục thực hiện được.' :
            'An error occurred while processing, the unit <span class="Highlight">{0}</span> has not been declared in account information.',
          c);
          break;
        case '4':
          msg = String.format(v ?
            'Khách hàng <span class="Highlight">{0}</span> chưa khai trong danh sách khách hàng sử dụng chứng từ điện tử, Chương trình không thể tiếp tục thực hiện được.' :
            'An error occurred while processing, the customer <span class="Highlight">{0}</span> has not been registered.',
          c);
          break;
        default:
          msg = (v ? 'Phát sinh lỗi trong quá trình thực hiện.' : 'The process was failed.');
          if (r.Reference) msg += String.format(' <span class="Highlight">{0}</span>', String.format(r.Message, r.Reference));
          break;
      }
    }
    else {
      var l = g._$k.length, n = r.Number;
      if (!n) refresh = false;
      msg = String.format(v ? 'Chương trình đã thực hiện xong, {0}/{1} chứng từ được cập nhật.' : 'The process was completed successfully, {0}/{1} record(s) has been updated.', n, l);
      if (r.Reference) msg += String.format(' <span class="Highlight">{0}</span>', String.format(r.Message, r.Reference));
    }
  }

  $func.hideWait(id);
  g._busy(false);
  $message.show(msg, String.format(refresh ? 'refresh$Page($find(\'{0}\'));' : '$find(\'{0}\')._focusWhenTabChanged();', id));
}

function onRequest$Failed(e, id) {
  var g = $find(id);
  $func.hideWait(id);
  g._busy(false);
  $message.showError(e);
}
function refresh$Page(g) {
  g._$process = g._$processOriginal;
  g._$k = [], g._$ld = [], g._$lvd = [], g._$c = [], a = [];
  g.goToPage(-1);
}
function isCheck$Grid(g) {
  var id = g.get_id(), msg = (g._language == 'v' ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  var limit = (g._language == 'v' ? String.format('Mỗi lần chỉ được phép phát hành tối đa <span class="Highlight">{0}</span> chứng từ.', g._$limitedInvoice) : String.format('Limit exceeded error, maximum number of vouchers is <span class="Highlight">{0}</span>.', g._$limitedInvoice));
  if (g._$k.length == 0) {
    $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
    return false;
  }
  if (g._unitProvider == '8' && g._$k.length > g._$limitedInvoice) {
    $message.show(limit, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
    return false;
  }
  return true;
}
function fill$Grid(g, f) {
  if (f && g._$k.length == 0) return;
  for (var r = 1; r <= g._rowCount; r++) {
    var k = row$Key(g, r, g._$i), i = Array.indexOf(g._$k, k);
    g._setItemValue(r, g._$t, (i > -1));
  }
}
function toggle$Grid(o) {
  var c = o.parentNode.parentNode.parentNode.id, g = $find($func.left(c, c.length - 11));
  for (var r = 1; r <= g._rowCount; r++) {
    if (!g._getItem(r, g._$t).disabled) {
      var k = row$Key(g, r, g._$i), l = row$Key(g, r, g._$x), m = row$Key(g, r, g._$y), n = row$Key(g, r, g._$z), i = Array.indexOf(g._$k, k);
      if (i == -1) Array.add(g._$k, k), Array.add(g._$ld, l), Array.add(g._$lvd, m), Array.add(g._$c, n);
        else Array.removeAt(g._$k, i), Array.removeAt(g._$ld, i), Array.removeAt(g._$lvd, i), Array.removeAt(g._$c, i);
      g._setItemValue(r, g._$t, (i == -1));
    }
  }

  if (g._rowCount <= 0) return;
  else {
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
    g._focusWhenTabChanged();
  }
}
function onChange$SelectedValue(o) {
  var a = o.id.split('_inputCell_'), g = o.grid;
  if (!g) g = $find(a[0]);
  var r = $func.getLocationCell(o)[0];
  var k = row$Key(g, r, g._$i), l = row$Key(g, r, g._$x), m = row$Key(g, r, g._$y), n = row$Key(g, r, g._$z), i = Array.indexOf(g._$k, k);
  if (i == -1) Array.add(g._$k, k), Array.add(g._$ld, l), Array.add(g._$lvd, m), Array.add(g._$c, n);
    else Array.removeAt(g._$k, i), Array.removeAt(g._$ld, i), Array.removeAt(g._$lvd, i), Array.removeAt(g._$c, i);

  g._activeRow = a[1].split('.')[0];
  g._activeColumn = a[1].split('.')[1];
  g._activeCell = g._getItem(g._activeRow, g._activeColumn);
}
function row$Key(g, r, c) {if (c == g._$y) {return g._getItemValue(r, c).z.format('yyyyMMdd');} else {return g._getItemValue(r, c);}}
function genHash(o) {
  var f = o.parentForm, p = $func.trim(MD5(o.value));
  f.getItem('chkpass').value = CRC32($func.trim(f._key).substr(0, 8) + p.substr(1, p.length - 2));
}
function checkFieldEntry(f, o, force) {
  if (force) o = f.getItem(o);
  var v = force ? o.value : o.oldValue;
  if (f._checked && !v) {
    f._checked = false;
    $func.hideWait(f.get_id());
    $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), o.field.Label), String.format('revertPassword(\'{0}\', \'\', true); $find(\'{0}\').focus(\'{1}\');', f.get_id(), o.field.Name));
  }
}
function revertPassword(f, name, force) {
  if (force) f = $find(f);
  var o = f.getItem('cpass');
